import React from "react";
import Loadable from "react-loadable";
import { Route, Switch, withRouter } from "react-router-dom";
import { SpinnerFlexButton } from "Util";

var Loading = () => <SpinnerFlexButton />;

const Home = Loadable({
  loader: () => import("./pages/Home"),
  loading: Loading
});
const WebApis = Loadable({
  loader: () => import("./pages/WebApis"),
  loading: Loading
});
const Auth = () => <div>Auth</div>;
const PortfolioDetail = () => <div>PortfolioDetail</div>;
const NoMatch = () => <div>NoMatch</div>;

class Routes extends React.Component {
  constructor(props) {
    super(props);
    this.state = {
      loggedInStatus: "NOT_LOGGED_IN"
    };
  }

  componentDidMount() {
    // console.log("componentDidMount: ", this);
  }

  render() {
    // console.log("this: ", this);
    return (
      <>
        {/* <NavigationContainer
              loggedInStatus={this.state.loggedInStatus}
              handleSuccessfulLogout={this.handleSuccessfulLogout}
            /> */}
        {/* <h1>{this.state.loggedInStatus}</h1> */}
        <main>
          <Switch>
            <Route exact path="/" component={Home} />
            <Route
              path="/auth"
              render={props => (
                <Auth
                  {...props}
                  handleSuccessfulLogin={this.handleSuccessfulLogin}
                  handleUnsuccessfulLogin={this.handleUnsuccessfulLogin}
                />
              )}
            />
            <Route path="/webapis" component={WebApis} />
            {this.state.loggedInStatus === "LOGGED_IN"
              ? this.authorizedPages()
              : null}
            <Route exact path="/portfolio/:slug" component={PortfolioDetail} />
            <Route component={NoMatch} />
          </Switch>
        </main>
      </>
    );
  }
}

// export default Routes;
export default withRouter(Routes);
